# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration backend that manages users, projects,
tasks, messaging, performance dashboards, ratings and exportable reports.

The implementation favours correctness, isolation (callers never receive a
live reference into the internal store) and concurrency safety: every public
operation runs under a single shared re-entrant lock so that cross-entity
invariants (such as the assignee index or globally unique identifiers) stay
consistent even under heavy parallel load.

Only the Python standard library is used.
"""

from __future__ import annotations

import copy
import csv
import io
import logging
import threading
from datetime import datetime
from enum import Enum

__all__ = [
    "TeamCollaborationManager",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ---------------------------------------------------------------------------
# Logging
# ---------------------------------------------------------------------------
logger = logging.getLogger("team_collaboration")
if not logger.handlers:  # pragma: no cover - defensive logging setup
    logger.addHandler(logging.NullHandler())


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Roles a user can hold within the system."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle state of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
class _Entity(object):
    """Common helpers shared by all stored entities."""

    def clone(self):
        """Return a deep, independent copy of this entity."""
        return copy.deepcopy(self)

    def __repr__(self):  # pragma: no cover - cosmetic only
        attrs = ", ".join(
            "{0}={1!r}".format(key, value)
            for key, value in sorted(self.__dict__.items())
        )
        return "{0}({1})".format(self.__class__.__name__, attrs)


class User(_Entity):
    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at


class Project(_Entity):
    def __init__(self, id, name, description, start_date, end_date, owner_id,
                 created_at):
        self.id = id
        self.name = name
        self.description = description
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id
        self.created_at = created_at


class Task(_Entity):
    def __init__(self, id, project_id, title, description="", assignee_id=None,
                 deadline=None, status=TaskStatus.NOT_STARTED, created_at=None,
                 started_at=None, completed_at=None):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.description = description
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.status = status
        self.created_at = created_at
        self.started_at = started_at
        self.completed_at = completed_at


class Attachment(_Entity):
    def __init__(self, filename, size, uploaded_by, uploaded_at, data=None):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at
        self.data = data


class Message(_Entity):
    def __init__(self, id, author_id, body, project_id=None, task_id=None,
                 parent_id=None, attachments=None, created_at=None,
                 edited_at=None):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = list(attachments) if attachments else []
        self.created_at = created_at
        self.edited_at = edited_at


class Rating(_Entity):
    def __init__(self, id, rater_id, ratee_id, score, feedback="",
                 task_id=None, created_at=None):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at


# ---------------------------------------------------------------------------
# Internal collections (each shares the manager's single lock)
# ---------------------------------------------------------------------------
class _Collection(object):
    """A minimal keyed store that carries a reference to the shared lock."""

    def __init__(self, lock):
        self._lock = lock
        self._items = {}


class _UserCollection(_Collection):
    pass


class _ProjectCollection(_Collection):
    pass


class _TaskCollection(_Collection):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_project = {}   # project_id -> set(task_id)
        self._by_assignee = {}  # user_id -> set(task_id)

    def _index_create(self, task):
        self._by_project.setdefault(task.project_id, set()).add(task.id)
        if task.assignee_id is not None:
            self._by_assignee.setdefault(task.assignee_id, set()).add(task.id)

    def _index_set_assignee(self, task, new_assignee_id):
        old = task.assignee_id
        if old is not None:
            bucket = self._by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    del self._by_assignee[old]
        if new_assignee_id is not None:
            self._by_assignee.setdefault(new_assignee_id, set()).add(task.id)

    def _index_remove(self, task):
        bucket = self._by_project.get(task.project_id)
        if bucket is not None:
            bucket.discard(task.id)
            if not bucket:
                del self._by_project[task.project_id]
        if task.assignee_id is not None:
            abucket = self._by_assignee.get(task.assignee_id)
            if abucket is not None:
                abucket.discard(task.id)
                if not abucket:
                    del self._by_assignee[task.assignee_id]


class _MessageCollection(_Collection):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_project = {}  # project_id -> set(message_id)
        self._by_task = {}     # task_id -> set(message_id)

    def _index_create(self, message):
        if message.project_id is not None:
            self._by_project.setdefault(message.project_id, set()).add(message.id)
        if message.task_id is not None:
            self._by_task.setdefault(message.task_id, set()).add(message.id)

    def _index_remove(self, message):
        if message.project_id is not None:
            bucket = self._by_project.get(message.project_id)
            if bucket is not None:
                bucket.discard(message.id)
                if not bucket:
                    del self._by_project[message.project_id]
        if message.task_id is not None:
            bucket = self._by_task.get(message.task_id)
            if bucket is not None:
                bucket.discard(message.id)
                if not bucket:
                    del self._by_task[message.task_id]


class _PerformanceCollection(_Collection):
    def __init__(self, lock):
        super().__init__(lock)
        self._ratings = {}    # rating_id -> Rating
        self._by_ratee = {}   # user_id -> set(rating_id)

    def _index_create(self, rating):
        self._ratings[rating.id] = rating
        self._by_ratee.setdefault(rating.ratee_id, set()).add(rating.id)

    def _ratings_for(self, user_id):
        ids = self._by_ratee.get(user_id, set())
        return [self._ratings[rid] for rid in sorted(ids)]


class _ReportCollection(_Collection):
    """Reports are computed on demand; this only carries the shared lock."""


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager(object):
    """Coordinates all collaboration operations behind a single shared lock."""

    def __init__(self, now=None):
        self._now_fn = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        # All collections deliberately share the manager's single lock so that
        # multi-collection operations remain atomic and consistent.
        self.users = _UserCollection(self._lock)
        self.projects = _ProjectCollection(self._lock)
        self.tasks = _TaskCollection(self._lock)
        self.messages = _MessageCollection(self._lock)
        self.performance = _PerformanceCollection(self._lock)
        self.reports = _ReportCollection(self._lock)

    # -- internal helpers ---------------------------------------------------
    def _now(self):
        return self._now_fn()

    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    @staticmethod
    def _is_blank(value):
        return value is None or not str(value).strip()

    @staticmethod
    def _valid_email(email):
        if email is None:
            return False
        email = email.strip()
        if not email or "@" not in email:
            return False
        local, _, domain = email.partition("@")
        return bool(local) and bool(domain)

    def _require_user(self, user_id):
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if self._is_blank(username):
                raise ValidationError("username must not be empty")
            if self._is_blank(email):
                raise ValidationError("email must not be empty")
            if not self._valid_email(email):
                raise ValidationError("email is not valid: {0!r}".format(email))
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            username = username.strip()
            email = email.strip()

            for existing in self.users._items.values():
                if existing.username == username:
                    raise DuplicateError(
                        "username already exists: {0}".format(username)
                    )
                if existing.email == email:
                    raise DuplicateError(
                        "email already exists: {0}".format(email)
                    )

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users._items[user.id] = user
            logger.info("registered user %s (%s)", user.id, user.username)
            return user.clone()

    def get_user(self, user_id):
        with self._lock:
            return self._require_user(user_id).clone()

    def list_users(self):
        with self._lock:
            return [
                self.users._items[uid].clone()
                for uid in sorted(self.users._items)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                if self._is_blank(username):
                    raise ValidationError("username must not be empty")
                username = username.strip()
                for other in self.users._items.values():
                    if other.id != user_id and other.username == username:
                        raise DuplicateError(
                            "username already exists: {0}".format(username)
                        )

            if email is not None:
                if not self._valid_email(email):
                    raise ValidationError(
                        "email is not valid: {0!r}".format(email)
                    )
                email = email.strip()
                for other in self.users._items.values():
                    if other.id != user_id and other.email == email:
                        raise DuplicateError(
                            "email already exists: {0}".format(email)
                        )

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            logger.info("updated user %s", user_id)
            return user.clone()

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)

            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user {0} owns project {1}".format(user_id, project.id)
                    )

            for task in self.tasks._items.values():
                if (task.assignee_id == user_id
                        and task.status != TaskStatus.COMPLETED):
                    raise ConflictError(
                        "user {0} has open task {1}".format(user_id, task.id)
                    )

            # Detach the user from any completed tasks they still hold so the
            # assignee index does not point at a deleted user.
            for task in self.tasks._items.values():
                if task.assignee_id == user_id:
                    self.tasks._index_set_assignee(task, None)
                    task.assignee_id = None

            del self.users._items[user_id]
            logger.info("deleted user %s", user_id)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id,
                       description=""):
        with self._lock:
            if self._is_blank(name):
                raise ValidationError("project name must not be empty")
            self._require_user(owner_id)
            if start_date is None or end_date is None:
                raise ValidationError("start_date and end_date are required")
            if end_date < start_date:
                raise ValidationError("end_date must not be before start_date")

            project = Project(
                id=self._next_id(),
                name=name.strip(),
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects._items[project.id] = project
            logger.info("created project %s (%s)", project.id, project.name)
            return project.clone()

    def get_project(self, project_id):
        with self._lock:
            return self._require_project(project_id).clone()

    def list_projects(self):
        with self._lock:
            return [
                self.projects._items[pid].clone()
                for pid in sorted(self.projects._items)
            ]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        with self._lock:
            project = self._require_project(project_id)

            if name is not None and self._is_blank(name):
                raise ValidationError("project name must not be empty")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not be before start_date")

            if name is not None:
                project.name = name.strip()
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            logger.info("updated project %s", project_id)
            return project.clone()

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            task_ids = list(self.tasks._by_project.get(project_id, set()))
            for task_id in task_ids:
                task = self.tasks._items.get(task_id)
                if task is not None:
                    self.tasks._index_remove(task)
                    del self.tasks._items[task_id]
                    self._delete_messages_for_task(task_id)

            message_ids = list(self.messages._by_project.get(project_id, set()))
            for message_id in message_ids:
                message = self.messages._items.get(message_id)
                if message is not None:
                    self.messages._index_remove(message)
                    del self.messages._items[message_id]

            del self.projects._items[project_id]
            logger.info("deleted project %s", project_id)

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, description="", assignee_id=None,
                    deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            if self._is_blank(title):
                raise ValidationError("task title must not be empty")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError(
                    "deadline must not be before the project start date"
                )

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title.strip(),
                description=description or "",
                assignee_id=assignee_id,
                deadline=deadline,
                status=TaskStatus.NOT_STARTED,
                created_at=self._now(),
            )
            self.tasks._items[task.id] = task
            self.tasks._index_create(task)
            logger.info("created task %s in project %s", task.id, project_id)
            return task.clone()

    def get_task(self, task_id):
        with self._lock:
            return self._require_task(task_id).clone()

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = self.tasks._by_project.get(project_id, set())
            return [self.tasks._items[tid].clone() for tid in sorted(ids)]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ids = self.tasks._by_assignee.get(user_id, set())
            return [self.tasks._items[tid].clone() for tid in sorted(ids)]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self.tasks._index_set_assignee(task, assignee_id)
            task.assignee_id = assignee_id
            logger.info("assigned task %s to user %s", task_id, assignee_id)
            return task.clone()

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self.tasks._index_set_assignee(task, new_assignee_id)
            task.assignee_id = new_assignee_id
            logger.info("reassigned task %s to user %s", task_id, new_assignee_id)
            return task.clone()

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            self.tasks._index_set_assignee(task, None)
            task.assignee_id = None
            logger.info("unassigned task %s", task_id)
            return task.clone()

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline must not be before the project start date"
                    )
            task.deadline = deadline
            logger.info("set deadline for task %s", task_id)
            return task.clone()

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            logger.info("task %s status -> %s", task_id, status.value)
            return task.clone()

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def _delete_messages_for_task(self, task_id):
        message_ids = list(self.messages._by_task.get(task_id, set()))
        for message_id in message_ids:
            message = self.messages._items.get(message_id)
            if message is not None:
                self.messages._index_remove(message)
                del self.messages._items[message_id]

    def _build_attachments(self, attachments, uploaded_by, uploaded_at):
        built = []
        for entry in attachments or []:
            filename, data = entry
            data_bytes = data if data is not None else b""
            built.append(
                Attachment(
                    filename=filename,
                    size=len(data_bytes),
                    uploaded_by=uploaded_by,
                    uploaded_at=uploaded_at,
                    data=bytes(data_bytes),
                )
            )
        return built

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None):
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )

            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            has_attachments = bool(attachments)
            if (body is None or not body.strip()) and not has_attachments:
                raise ValidationError(
                    "message body must not be empty without attachments"
                )

            now = self._now()
            built_attachments = self._build_attachments(
                attachments, author_id, now
            )
            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body if body is not None else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=now,
                edited_at=None,
            )
            self.messages._items[message.id] = message
            self.messages._index_create(message)
            logger.info("posted message %s", message.id)
            return message.clone()

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError(
                    "only the author may edit this message"
                )
            has_attachments = bool(message.attachments)
            if (new_body is None or not new_body.strip()) and not has_attachments:
                raise ValidationError(
                    "message body must not be empty without attachments"
                )
            message.body = new_body if new_body is not None else ""
            message.edited_at = self._now()
            logger.info("edited message %s", message_id)
            return message.clone()

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may add attachments"
                )
            if self._is_blank(filename):
                raise ValidationError("filename must not be empty")

            data_bytes = data if data is not None else b""
            attachment = Attachment(
                filename=filename,
                size=len(data_bytes),
                uploaded_by=uploader_id,
                uploaded_at=self._now(),
                data=bytes(data_bytes),
            )
            message.attachments.append(attachment)
            logger.info("added attachment to message %s", message_id)
            return message.clone()

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = self.messages._by_project.get(project_id, set())
            return [self.messages._items[mid].clone() for mid in sorted(ids)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            ids = self.messages._by_task.get(task_id, set())
            return [self.messages._items[mid].clone() for mid in sorted(ids)]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete this message"
                )
            self.messages._index_remove(message)
            del self.messages._items[message_id]
            logger.info("deleted message %s", message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _tasks_for_user(self, user_id):
        ids = self.tasks._by_assignee.get(user_id, set())
        return [self.tasks._items[tid] for tid in sorted(ids)]

    def _completion_rate(self, tasks):
        if not tasks:
            return 0.0
        completed = sum(
            1 for task in tasks if task.status == TaskStatus.COMPLETED
        )
        return completed / len(tasks)

    def _average_completion_time(self, tasks):
        durations = []
        for task in tasks:
            if (task.status == TaskStatus.COMPLETED
                    and task.started_at is not None
                    and task.completed_at is not None):
                delta = task.completed_at - task.started_at
                durations.append(delta.total_seconds())
        if not durations:
            return None
        return sum(durations) / len(durations)

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._completion_rate(self._tasks_for_user(user_id))

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time(self._tasks_for_user(user_id))

    def submit_rating(self, rater_id, ratee_id, score, feedback="",
                      task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback if feedback is not None else "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._index_create(rating)
            logger.info("rating %s submitted for user %s", rating.id, ratee_id)
            return rating.clone()

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self.performance._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [r.clone() for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            ratings = self.performance._ratings_for(user_id)

            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            ids = self.tasks._by_project.get(project_id, set())
            tasks = [self.tasks._items[tid] for tid in sorted(ids)]
            now = self._now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (task.deadline is not None
                        and task.status != TaskStatus.COMPLETED
                        and now > task.deadline):
                    overdue += 1
                if task.assignee_id is not None:
                    per_assignee.setdefault(task.assignee_id, []).append(task)

            per_assignee_summary = {}
            for assignee_id, assigned in per_assignee.items():
                assigned_completed = sum(
                    1 for t in assigned if t.status == TaskStatus.COMPLETED
                )
                per_assignee_summary[assignee_id] = {
                    "total": len(assigned),
                    "completed": assigned_completed,
                    "completion_rate": self._completion_rate(assigned),
                }

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": len(tasks),
                "status_counts": status_counts,
                "completion_rate": self._completion_rate(tasks),
                "overdue_tasks": overdue,
                "per_assignee": per_assignee_summary,
            }

    def _user_metrics_row(self, user_id, tasks):
        completed = sum(
            1 for t in tasks if t.status == TaskStatus.COMPLETED
        )
        ratings = self.performance._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count
            if rating_count else 0.0
        )
        user = self.users._items.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user is not None else "",
            "total_tasks": len(tasks),
            "completed_tasks": completed,
            "completion_rate": self._completion_rate(tasks),
            "average_completion_time": self._average_completion_time(tasks),
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                ids = self.tasks._by_project.get(project_id, set())
                scoped_tasks = [self.tasks._items[tid] for tid in ids]
            else:
                scoped_tasks = list(self.tasks._items.values())

            by_user = {}
            for task in scoped_tasks:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                tasks = sorted(by_user[user_id], key=lambda t: t.id)
                rows.append(self._user_metrics_row(user_id, tasks))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            ratings = self.performance._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count else 0.0
            )
            user = self.users._items[user_id]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": len(tasks),
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": [t.clone() for t in tasks],
            }

    # -- export -------------------------------------------------------------
    def export_report(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")

        if report_format == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    @staticmethod
    def _format_value(value):
        if value is None:
            return ""
        if isinstance(value, float):
            return repr(value)
        return value

    def _csv_table(self, report):
        rtype = report.get("report_type")
        if rtype == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_count", "rating_average",
            ]
            rows = [header]
            for row in report.get("rows", []):
                rows.append([self._format_value(row.get(key)) for key in header])
            return rows

        if rtype == ReportType.PROJECT_PROGRESS.value:
            status_counts = report.get("status_counts", {})
            header = [
                "project_id", "total_tasks", "completion_rate", "overdue_tasks",
            ] + list(status_counts.keys())
            row = [
                self._format_value(report.get("project_id")),
                self._format_value(report.get("total_tasks")),
                self._format_value(report.get("completion_rate")),
                self._format_value(report.get("overdue_tasks")),
            ] + [self._format_value(status_counts[key]) for key in status_counts]
            return [header, row]

        if rtype == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "in_progress_tasks", "not_started_tasks", "completion_rate",
                "average_completion_time", "rating_count", "rating_average",
            ]
            row = [self._format_value(report.get(key)) for key in header]
            return [header, row]

        # Generic fallback: key/value pairs for any unknown report shape.
        rows = [["key", "value"]]
        for key, value in report.items():
            if isinstance(value, (list, dict)):
                rows.append([key, self._format_value(len(value))])
            else:
                rows.append([key, self._format_value(value)])
        return rows

    def _export_csv(self, report):
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        for row in self._csv_table(report):
            writer.writerow(row)
        return buffer.getvalue()

    def _pdf_lines(self, report):
        lines = []
        rtype = report.get("report_type", "report")
        lines.append("Report: {0}".format(rtype))
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, list):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
                if value and all(isinstance(v, dict) for v in value):
                    for entry in value:
                        parts = ", ".join(
                            "{0}={1}".format(k, self._format_value(v))
                            for k, v in entry.items()
                        )
                        lines.append("  - {0}".format(parts))
            elif isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append(
                        "  {0}: {1}".format(
                            sub_key, self._format_value(sub_value)
                        )
                    )
            else:
                lines.append("{0}: {1}".format(key, self._format_value(value)))
        return lines

    def _export_pdf(self, report):
        return _build_pdf(self._pdf_lines(report))


# ---------------------------------------------------------------------------
# Minimal, dependency-free PDF writer
# ---------------------------------------------------------------------------
def _build_pdf(lines):
    """Build a minimal but structurally valid single-page PDF document."""

    def escape(text):
        return (
            str(text)
            .replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )

    content_parts = ["BT", "/F1 12 Tf", "72 760 Td", "14 TL"]
    first = True
    safe_lines = lines if lines else [""]
    for line in safe_lines:
        if first:
            content_parts.append("({0}) Tj".format(escape(line)))
            first = False
        else:
            content_parts.append("T*")
            content_parts.append("({0}) Tj".format(escape(line)))
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        (
            b"<< /Length " + str(len(content)).encode("ascii")
            + b" >>\nstream\n" + content + b"\nendstream"
        ),
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray()
    pdf += b"%PDF-1.4\n"
    offsets = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(index).encode("ascii")
        pdf += body
        pdf += b"\nendobj\n"

    xref_offset = len(pdf)
    size = len(objects) + 1
    pdf += "xref\n0 {0}\n".format(size).encode("ascii")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += b"trailer\n"
    pdf += "<< /Size {0} /Root 1 0 R >>\n".format(size).encode("ascii")
    pdf += b"startxref\n"
    pdf += "{0}\n".format(xref_offset).encode("ascii")
    pdf += b"%%EOF"
    return bytes(pdf)
